#include <stdio.h>
#include <string.h>

int build_messages(char *buf1, char *buf2, char *buf3, size_t sz) {
    int code = 404;
    char *status = "Not Found";
    double temp = 36.6;
    snprintf(buf1, sz, "Error %d: %s", code, status);
    snprintf(buf2, sz, "Temp: %.1f C", temp);
    snprintf(buf3, sz, "%s | %s", buf1, buf2);
    return strlen(buf1);
}

int main(void) {
    {
        char buf1[64], buf2[64], buf3[64];
        build_messages(buf1, buf2, buf3, 64);
        printf("%s\n", buf1);
    }
    {
        char buf1[64], buf2[64], buf3[64];
        build_messages(buf1, buf2, buf3, 64);
        printf("%s\n", buf2);
    }
    {
        char buf1[64], buf2[64], buf3[64];
        build_messages(buf1, buf2, buf3, 64);
        printf("%s\n", buf3);
    }
    {
        char buf1[64], buf2[64], buf3[64];
        int len = build_messages(buf1, buf2, buf3, 64);
        printf("%d\n", (int)(len));
    }
    return 0;
}

